scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{

		if (GlidePluginManager.isActive('sn_genai_platform') == false)
		{
			return;
		}

		var GetRecord = x_snc_devtools.GetRecord;
		var IsValidRecord = x_snc_devtools.IsValidRecord;
		var GetStringValue = x_snc_devtools.GetStringValue;

		var grAgent = GetRecord('sn_aia_agent',current.agent);
		if (IsValidRecord(grAgent) == false)
		{
			engine.finding.increment();
			return;
		}
		var strAgentName = GetStringValue(grAgent.name);

		var grTool = GetRecord('sn_aia_tool',current.tool);
		if (IsValidRecord(grTool) == false)
		{
			engine.finding.increment();
			return;
		}

		// The naming convention only applies if there are multiple agents in the same scope
		var grAgents = new GlideRecord('sn_aia_agent');
		grAgents.addQuery('sys_scope','=',current.sys_scope);
		grAgents.query();
		if (grAgents.getRowCount() < 2)
		{
			return;
		} 

		var strToolName = GetStringValue(grTool.name);

		if (strToolName.indexOf(strAgentName + ' - ') != 0)
		{
			engine.finding.increment();
			return;
		}

		var strAgentToolName = GetStringValue(current.name);
		if (strAgentToolName != strToolName)
		{
			engine.finding.increment();
			return;
		}
	}

})(engine);
